import React from "react";
import { Link } from "react-router-dom";

interface LogoProps {
  style: string;
  imgSrc: string;
  width: number;
  height: number;
}

const Logo: React.FC<LogoProps> = ({ style, imgSrc, width, height }) => {
  return (
    <Link to="/">
      <img
        className={style}
        src={imgSrc}
        width={width}
        height={height}
        alt="logo"
      />
    </Link>
  );
};
export default Logo;

